import numpy as np

# Define the Checkers class

class Draughts:
    def __init__(self):
        self.board = np.array([
            ['b', ' ', 'b', ' ', 'b', ' ', 'b', ' '],
            [' ', 'b', ' ', 'b', ' ', 'b', ' ', 'b'],
            ['b', ' ', 'b', ' ', 'b', ' ', 'b', ' '],
            [' ', ' ', ' ', ' ', ' ', ' ', ' ', ' '],
            [' ', ' ', ' ', ' ', ' ', ' ', ' ', ' '],
            ['r', ' ', 'r', ' ', 'r', ' ', 'r', ' '],
            [' ', 'r', ' ', 'r', ' ', 'r', ' ', 'r'],
            ['r', ' ', 'r', ' ', 'r', ' ', 'r', ' ']
        ])
        self.current_player = 'b'

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    def is_valid_move(self, start, end):
        if start[0] < 0 or start[1] < 0 or start[0] >= 8 or start[1] >= 8 or end[0] < 0 or end[1] < 0 or end[0] >= 8 or end[1] >= 8:
            return False
        if self.board[start[0], start[1]] == ' ' or self.board[end[0], end[1]] != ' ':
            return False
        dx, dy = end[0] - start[0], end[1] - start[1]
        if abs(dx) != 1 or abs(dy) not in [1, 2]:
            return False
        if self.current_player == 'b':
            if self.board[start[0], start[1]] == 'b' and dy != 1:
                return False
        else:
            if self.board[start[0], start[1]] == 'r' and dy != -1:
                return False
        if abs(dx) == 2:
            mid = (start[0] + end[0]) // 2, (start[1] + end[1]) // 2
            if self.board[mid[0], mid[1]] == ' ' or self.board[mid[0], mid[1]].lower() == self.current_player.lower():
                return False
        return True

    def make_move(self, start, end):
        if not self.is_valid_move(start, end):
            raise ValueError("Invalid move")
        dx, dy = end[0] - start[0], end[1] - start[1]
        mid = None
        if abs(dx) == 2:
            mid = (start[0] + end[0]) // 2, (start[1] + end[1]) // 2
            self.board[mid[0], mid[1]] = ' '
        self.board[start[0], start[1]], self.board[end[0], end[1]] = ' ', self.board[start[0], start[1]]
        if abs(end[0] - start[0]) == 2:
            self.current_player = 'r' if self.current_player == 'b' else 'b'
        elif end[0] == 0 and self.current_player == 'b' or end[0] == 7 and self.current_player == 'r':
            self.board[end[0], end[1]] = 'B' if self.current_player == 'b' else 'R'

    def is_game_over(self):
        player_pieces = np.sum((self.board == 'b').astype(int))
        opponent_pieces = np.sum((self.board == 'r').astype(int))
        return player_pieces == 0 or opponent_pieces == 0

# Example usage
if __name__ == "__main__":
    game = Draughts()
